import React from "react";

interface ArticleSchemaProps {
  type: "article";
  title: string;
  description: string;
  url: string;
  publishedTime: string;
  author: string;
  authorUrl?: string;
  image?: string;
  siteUrl: string;
  siteName: string;
  category?: string;
  tags?: string[];
}

interface WebSiteSchemaProps {
  type: "website";
  url: string;
  name: string;
  description: string;
}

interface BreadcrumbItem {
  name: string;
  url: string;
}

interface BreadcrumbSchemaProps {
  type: "breadcrumb";
  items: BreadcrumbItem[];
}

type Props = ArticleSchemaProps | WebSiteSchemaProps | BreadcrumbSchemaProps;

const JsonLd: React.FC<Props> = (props: Props) => {
  let schema: object;

  if (props.type === "article") {
    schema = {
      "@context": "https://schema.org",
      "@type": "BlogPosting",
      headline: props.title,
      description: props.description,
      url: props.url,
      datePublished: props.publishedTime,
      author: {
        "@type": "Person",
        name: props.author,
        url: props.authorUrl || props.siteUrl,
      },
      publisher: {
        "@type": "Person",
        name: props.author,
        url: props.authorUrl || props.siteUrl,
      },
      mainEntityOfPage: {
        "@type": "WebPage",
        "@id": props.url,
      },
      ...(props.image && { image: props.image }),
      ...(props.category && { articleSection: props.category }),
      ...(props.tags?.length && { keywords: props.tags.join(", ") }),
    };
  } else if (props.type === "website") {
    schema = {
      "@context": "https://schema.org",
      "@type": "WebSite",
      url: props.url,
      name: props.name,
      description: props.description,
    };
  } else {
    schema = {
      "@context": "https://schema.org",
      "@type": "BreadcrumbList",
      itemListElement: props.items.map((item, index) => ({
        "@type": "ListItem",
        position: index + 1,
        name: item.name,
        item: item.url,
      })),
    };
  }

  return (
    <script
      type="application/ld+json"
      dangerouslySetInnerHTML={{ __html: JSON.stringify(schema) }}
    />
  );
};

export default JsonLd;
